CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260715151634_Initial') THEN
    CREATE TABLE "Clients" (
        "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
        "Address" character varying(500) NOT NULL,
        "IsArchive" boolean NOT NULL,
        "Name" character varying(200) NOT NULL,
        CONSTRAINT "PK_Clients" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260715151634_Initial') THEN
    CREATE TABLE "Incomes" (
        "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
        "Number" character varying(50) NOT NULL,
        "Date" date NOT NULL,
        CONSTRAINT "PK_Incomes" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260715151634_Initial') THEN
    CREATE TABLE "Resources" (
        "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
        "IsArchive" boolean NOT NULL,
        "Name" character varying(200) NOT NULL,
        CONSTRAINT "PK_Resources" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260715151634_Initial') THEN
    CREATE TABLE "Units" (
        "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
        "IsArchive" boolean NOT NULL,
        "Name" character varying(200) NOT NULL,
        CONSTRAINT "PK_Units" PRIMARY KEY ("Id")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260715151634_Initial') THEN
    CREATE TABLE "Shipments" (
        "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
        "Number" character varying(50) NOT NULL,
        "Date" date NOT NULL,
        "ClientId" bigint NOT NULL,
        "IsApprove" boolean NOT NULL,
        CONSTRAINT "PK_Shipments" PRIMARY KEY ("Id"),
        CONSTRAINT "FK_Shipments_Clients_ClientId" FOREIGN KEY ("ClientId") REFERENCES "Clients" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260715151634_Initial') THEN
    CREATE TABLE "Balances" (
        "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
        "ResourceId" bigint NOT NULL,
        "UnitId" bigint NOT NULL,
        "Quantity" bigint NOT NULL,
        CONSTRAINT "PK_Balances" PRIMARY KEY ("Id"),
        CONSTRAINT "ValidQuantity" CHECK ("Quantity" > 0),
        CONSTRAINT "FK_Balances_Resources_ResourceId" FOREIGN KEY ("ResourceId") REFERENCES "Resources" ("Id") ON DELETE CASCADE,
        CONSTRAINT "FK_Balances_Units_UnitId" FOREIGN KEY ("UnitId") REFERENCES "Units" ("Id") ON DELETE CASCADE
    );
    END IF;
END $EF$;

DO $EF$
