        "UnitId" bigint NOT NULL,
        "Quantity" bigint NOT NULL,
        CONSTRAINT "PK_IncomeItems" PRIMARY KEY ("Id"),
        CONSTRAINT "ValidQuantity" CHECK ("Quantity" > 0),
        CONSTRAINT "FK_IncomeItems_Incomes_IncomeId" FOREIGN KEY ("IncomeId") REFERENCES "Incomes" ("Id"),
        CONSTRAINT "FK_IncomeItems_Resources_ResourceId" FOREIGN KEY ("ResourceId") REFERENCES "Resources" ("Id") ON DELETE CASCADE,
        CONSTRAINT "FK_IncomeItems_Units_UnitId" FOREIGN KEY ("UnitId") REFERENCES "Units" ("Id") ON DELETE CASCADE
